then.script:
var payload = mc.getPayloadJSON();
var claimResponse = null;
var policyResponse = null;
var vinResponse = null;
var driverResponse = null;

// Read property (currently string)
var claimRequest = mc.getProperty("claimResponse");

// Convert stringified JSON to proper JSON object
if (claimRequest && typeof claimRequest === "string") {
    claimRequest = JSON.parse(claimRequest);
}

// If the structure is { "claimRequest": {...} } and you want only inner object
if (claimRequest && claimRequest.claimRequest) {
    claimRequest = claimRequest.claimRequest;
}

payload.forEach(function (item) {
    if (item.claimsByPolicyHolderResponse) claimResponse = item.claimsByPolicyHolderResponse;
    if (item.policyResponse) policyResponse = item.policyResponse;
    if (item.vinResponse) vinResponse = item.vinResponse;
    if (item.driverResponse) driverResponse = item.driverResponse;
});

if (!claimResponse || !policyResponse) throw "Mandatory backend response missing";

// ✅ Build aggregated response
var aggregatedResponse = {
    claimRequest: claimRequest,
    claim: claimResponse,
    policy: policyResponse,
    vin: vinResponse,
    driver: driverResponse
};
var aggregatedResponse = {
    claimRequest: claimRequest,
    claim: claimResponse,
    policy: policyResponse,
    vin: vinResponse,
    driver: driverResponse
};

mc.setProperty("aggregatedResponse", JSON.stringify(aggregatedResponse));

// ==================================
// READ AGGREGATED RESPONSE
// ===================================

var aggregatedResponse = mc.getProperty("aggregatedResponse");

if (typeof aggregatedResponse === "string") {
    aggregatedResponse = JSON.parse(aggregatedResponse);
}

// Read payload as lossPayload
var lossPayload = mc.getPayloadJSON();

var approvedAmount = 0;

if (lossPayload &&
    lossPayload.assessment &&
    lossPayload.assessment.netPayableAmount != null) {

    approvedAmount = parseFloat(lossPayload.assessment.netPayableAmount) || 0;
}

// ==============================
// EXTRACT OBJECTS (UNCHANGED)
// ==============================

var claimRequest = aggregatedResponse.claimRequest || null;
var policy = aggregatedResponse.policy || null;
var vinResponse = aggregatedResponse.vin || null;
var driverResponse = aggregatedResponse.driver || null;
var claimData = aggregatedResponse.claim || null;

if (!claimRequest) throw "claimRequest not found";
if (!policy) throw "policy not found";


// ==============================
// HANDLE ARRAY (CRITICAL FIX)
// ==============================

if (Array.isArray(claimRequest)) {
    claimRequest = claimRequest[0];
}


// =============================
// DATE HELPERS
// =============================

function parseDate(val) {
    if (!val) return null;
    if (val.indexOf("Z") === -1)
        val = val + "Z";
    return new Date(val);
}

function parseEndOfDay(val) {
    if (!val) return null;
    return new Date(val.split("T")[0] + "T23:59:59Z");
}

function addDays(date, days) {
    var d = new Date(date);
    d.setDate(d.getDate() + days);
    return d;
}


// ================================
// READ DATES
// ================================

var claimIntimationDate =
    parseDate(claimRequest.claimIntimationDate);

var incidentDate =
    parseDate(claimRequest.incidentDateTime);

var licenseExpiry =
    parseEndOfDay(
        driverResponse &&
        driverResponse.expirationDate
    );


// ========================================
// POLICY VALIDATION (USING TERM START DATE)
// ========================================

var policyStartDate =
    parseDate(policy.termStartDate);

var policyEndDate =
    parseDate(policy.termEndDate);

var policyValidation = "Invalid";

if (policyEndDate && claimIntimationDate) {

    var startPlus24Hours =
        policyStartDate ? addDays(policyStartDate, 1) : null;

    if (policyEndDate > claimIntimationDate &&
        (!startPlus24Hours || startPlus24Hours < claimIntimationDate)) {

        policyValidation = "Valid";

    }
    else if (startPlus24Hours &&
             startPlus24Hours > claimIntimationDate) {

        policyValidation =
            "A claim cannot be raised within 24 hours of policy start date";
    }
}


// ===================================
// VEHICLE VALIDATION
// ===================================

var vehicleValidation = "Invalid";

var backendVIN =
    vinResponse &&
    vinResponse.length > 0 &&
    vinResponse[0].VIN
        ? vinResponse[0].VIN
        : null;

if (!backendVIN) {

    vehicleValidation =
        "VIN validation failed for VIN Number : " +
        (claimRequest.vehicleDetails && claimRequest.vehicleDetails.vin);

} else {

    vehicleValidation = "Valid";
}


// ======================================
// DRIVER VALIDATION
// ======================================

var driverValidation = "Valid";

if (incidentDate &&
    licenseExpiry &&
    incidentDate > licenseExpiry) {

    driverValidation =
        "The driving license for license Number : " +
        (driverResponse && driverResponse.licenseNumber) +
        " has expired on date " +
        (driverResponse && driverResponse.expirationDate);
}
// ============================================================
// COVERAGE VALIDATION (FIXED AS PER ACTUAL STRUCTURE)
// ============================================================

var coverageValidation = "Invalid";

// Requested coverage → from claimRequest (array-safe)
var requestedCoverageId =
    claimRequest &&
    claimRequest.policy &&
    claimRequest.policy.insurableObjects &&
    claimRequest.policy.insurableObjects[0] &&
    claimRequest.policy.insurableObjects[0].coverage &&
    claimRequest.policy.insurableObjects[0].coverage[0] &&
    claimRequest.policy.insurableObjects[0].coverage[0].coverageIdentifier;

// Policy coverage → from policy response
var policyCoverageId =
    policy &&
    policy.insurableObjects &&
    policy.insurableObjects[0] &&
    policy.insurableObjects[0].coverages &&
    policy.insurableObjects[0].coverages[0] &&
    policy.insurableObjects[0].coverages[0].coverageIdentifier;

// DW equivalent logic
if (!requestedCoverageId) {

    coverageValidation = "Invalid";

}
else if (policyCoverageId === requestedCoverageId) {

    coverageValidation = "Valid";

}
else {

    coverageValidation = "Invalid";
}
// ======================================
// FRAUD RISK (DW ALIGNED)
// ======================================

var fraudRisk = "High";

var rejectedClaims =
    claimRequest.claimStats &&
    claimRequest.claimStats.rejectedClaims;

if (rejectedClaims > 5) {

    fraudRisk = "Medium";

} else if (rejectedClaims > 0) {

    fraudRisk = "Low";

} else {

    fraudRisk = "High";
}


// ==========================================
// VALIDATION STATUS
// ==========================================

var validationStatus =
    (policyValidation === "Valid" &&
     vehicleValidation === "Valid" &&
     driverValidation === "Valid" &&
     coverageValidation === "Valid")
        ? "Passed"
        : "Failed";


// =======================================
// FINAL RESPONSE
// =======================================

mc.setPayloadJSON({

    policy: policyValidation,
    vehicle: vehicleValidation,
    driver: driverValidation,
    coverage: coverageValidation,
    fraudRisk: fraudRisk,
    validationStatus: validationStatus,
    approvedAmount: approvedAmount

});
